前言鉴于我为C++学习还是付出了蛮多的,打算把我的主要学习代码汇总一下(๑╹◡╹)ﾉ”””部分代码为便于学习,使用AI添加了可读性较好的注释,部分代码注释是跟课程敲的代码,所以在下面又重写了一遍
STLSTL_map#include&lt;iostream&gt;#include&lt;map&gt;#include&lt;vector&gt;#include&lt;string&gt;using namespace std;int main()&#123;	map&lt;int, int&gt;mp;	mp[1] = 3;	mp[7] = 98;	mp[99] = 57;	mp[3] = 1;	mp.erase(3);	mp[2] = 1;//键可以有多个值,但一个值不能被两个键映射	cout &lt;&lt; mp[2] &lt;&lt; endl;//查找键是否存在	cout &lt;&lt; mp.count(2) &lt;&lt; endl;	if (mp.find(1) != mp.end())	&#123;		cout &lt;&lt; &quot;yes&quot; &lt;&lt; endl;	&#125;	else	&#123;		cout &lt;&lt; &quot;no&quot; &lt;&lt; endl;	&#125;	for (map&lt;int, int&gt;::iterator it = mp.begin(); it != mp.end(); ++it)	&#123;		cout &lt;&lt; it-&gt;first &lt;&lt;&quot; &quot; &lt;&lt; it-&gt;second &lt;&lt; &quot; &quot;;	&#125;	cout &lt;&lt; endl;	for (auto num : mp)	&#123;		cout &lt;&lt; num.first &lt;&lt; &#x27; &#x27; &lt;&lt; num.second &lt;&lt; &#x27; &#x27;;	&#125;	vector&lt;string&gt;word = &#123;&quot;AAA&quot;,&quot;AAA&quot;,&quot;bbb&quot;,&quot;bbb&quot;,&quot;bbb&quot;&#125;;	map&lt;string, int&gt;count;	for (int i = 0; i &lt; word.size(); ++i)	&#123;		count[word[i]]++;	&#125;	for (map&lt;string, int&gt;::iterator it = count.begin(); it != count.end(); ++it)	&#123;		cout &lt;&lt; it-&gt;first &lt;&lt; &quot; &quot; &lt;&lt; it-&gt;second &lt;&lt; endl;			&#125;&#125;
STL_pair#include&lt;iostream&gt;#include&lt;utility&gt;using namespace std;int main()&#123;	pair&lt;int, int&gt;p1 = &#123;1,2&#125;;	pair&lt;int, int&gt;p2 = &#123; 1,2 &#125;;	if (p1 == p2)	&#123;		cout &lt;&lt; &quot;yes&quot; &lt;&lt; endl;	&#125;	cout &lt;&lt; p1.first &lt;&lt; &quot; &quot; &lt;&lt; p.second;	pair&lt;pair&lt;char, int&gt;, int&gt;;//三元组&#125;
STL_queue#include&lt;iostream&gt;#include&lt;queue&gt;using namespace std;int main()&#123;	queue&lt;int&gt; q;	q.push(10);	q.push(20);	q.push(30);	cout &lt;&lt; q.front() &lt;&lt; endl;	cout &lt;&lt; q.back() &lt;&lt; endl;	q.pop();	cout &lt;&lt; q.front() &lt;&lt; endl;	cout &lt;&lt; q.back() &lt;&lt; endl;	cout &lt;&lt; q.size() &lt;&lt; endl;	cout &lt;&lt; q.empty() &lt;&lt; endl;	return 0;&#125;
STL_set#include&lt;iostream&gt;#include&lt;set&gt;#include&lt;vector&gt;using namespace std;int main()&#123;	set&lt;int&gt;st;	st.insert(1);	st.insert(0);	st.insert(1);	st.insert(2);	st.erase(2);	if (st.count(1))	&#123;		cout &lt;&lt; &quot;yes&quot; &lt;&lt; endl;	&#125;	if (st.find(1) != st.end())	&#123;		cout &lt;&lt; &quot;yes&quot; &lt;&lt; endl;	&#125;	for (int num : st)	&#123;		cout &lt;&lt; num &lt;&lt; endl;	&#125;	//迭代器	for (set&lt;int&gt;::iterator it = st.begin(); it != st.end(); ++it)	&#123;		cout &lt;&lt; *it &lt;&lt; endl;	&#125;	//基于范围的for循环	for (auto &amp;num : st)	&#123;		cout &lt;&lt; num &lt;&lt; endl;	&#125;	vector&lt;int&gt;nums = &#123; 3,4,2,7,9,6,7,5,5,8&#125;;	for (int i=0;i&lt;nums.size();++i)	&#123;		st.insert(nums[i]);	&#125;	//set为集合,可以用来去重和排序	for (set&lt;int&gt;::iterator it = st.begin(); it != st.end(); ++it)	&#123;		cout &lt;&lt; *it &lt;&lt; &quot; &quot;;	&#125;	//不存在下标索引,元素只读,不可改写	return 0;&#125;
STL_stack#include&lt;iostream&gt;#include&lt;stack&gt;using namespace std;int main() &#123;	stack&lt;double&gt; stk;	stk.push(1.1);	stk.push(1.4);	cout &lt;&lt; stk.size() &lt;&lt; endl;	cout &lt;&lt; stk.empty() &lt;&lt; endl;	cout &lt;&lt; stk.top() &lt;&lt; endl;	stk.pop();	return 0;&#125;
STL_string#include&lt;iostream&gt;#include&lt;string&gt;using namespace std;int main()&#123;	string s1;	cin &gt;&gt; s1;	cout &lt;&lt; s1;	string s2(100, &#x27;0&#x27;);	s2 = &quot;awa&quot;;	s2[0] = &#x27;b&#x27;;	cout &lt;&lt; s2 &lt;&lt; endl;	cout &lt;&lt; s1 + s2 &lt;&lt; endl;	string s3 = &quot;123123123&quot;;	cout &lt;&lt; s1.substr(3,4) &lt;&lt; endl;//从第三位取长度为四的字串,起点下标;子串长度	if (s3.find(&quot;312&quot;) != string::npos)	&#123;		cout &lt;&lt; &quot;yes&quot; &lt;&lt; endl;	&#125;	string s4 = &quot;123123123&quot;;	int x = stoi(s4);	cout &lt;&lt; x &lt;&lt; endl;	//float x = stof(s4);以此类推	int y = 66663;	string s5 = to_string(x);	cout &lt;&lt; s5 &lt;&lt; endl;&#125;
STL_vector#include&lt;iostream&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;using namespace std;int main()&#123;	//vector&lt;数据类型&gt;array(长度,初值)	vector&lt;int&gt;vec1 = &#123;9,5,8,0,3,7,1,4,6,2&#125;;	vector&lt;double&gt;vec2(100,1);	vector&lt;vector&lt;int&gt;&gt;vec3(5, vector&lt;int&gt;(6));	vec1.push_back(2);	vec1.pop_back();	cout &lt;&lt; vec1.size()&lt;&lt;endl;	//vec1.clear();	cout&lt;&lt;vec1.empty()&lt;&lt;endl;	vec1.resize(13,3);	sort(vec1.begin(), vec1.end());	for (int n : vec1) &#123;		cout &lt;&lt; n &lt;&lt; &quot; &quot;;	&#125;	cout &lt;&lt; &quot;\n&quot;;&#125;
STL_迭代器#include&lt;iostream&gt;#include&lt;vector&gt;using namespace std;int main()&#123;	vector&lt;int&gt;a=&#123;1,2,3,4&#125;;	for (vector&lt;int&gt;::iterator it = a.begin(); it != a.end(); ++it)	&#123;		cout &lt;&lt; *it &lt;&lt; endl;	&#125;	for (vector&lt;int&gt;::reverse_iterator it = a.rbegin(); it != a.rend(); ++it)	&#123;		cout &lt;&lt; *it &lt;&lt; endl;	&#125;	cout &lt;&lt; a.end() - a.begin();	//prev(it)返回it的前一个迭代器	//next(it)返回it的下一个迭代器 &#125;
STL_算法#include &lt;iostream&gt;#include &lt;algorithm&gt;   // sort, swap, reverse, unique, lower_bound#include &lt;vector&gt;#include &lt;cmath&gt;       // 数学函数using namespace std;/* ============================================================ * 手写最大公约数 gcd（欧几里得算法） * 原理： *   gcd(a, b) = gcd(b, a % b) *   当 b == 0 时，a 即为最大公约数 * 特点： *   1. 时间复杂度 O(log n) *   2. 竞赛与工程中最常用写法 * ============================================================ */int gcd(int a, int b)&#123;    while (b != 0)    &#123;        int r = a % b;  // 余数        a = b;        b = r;    &#125;    return a;&#125;/* ============================================================ * 手写最小公倍数 lcm * 数学关系： *   a * b = gcd(a, b) * lcm(a, b) * 注意： *   必须先除 gcd 再乘，防止整数溢出 * ============================================================ */int lcm(int a, int b)&#123;    return a / gcd(a, b) * b;&#125;/* ============================================================ * 自定义比较器： *   1. pair.second 升序 *   2. 若 second 相同，则 pair.first 降序 * ============================================================ */bool cmp(pair&lt;int, int&gt; a, pair&lt;int, int&gt; b)&#123;    if (a.second != b.second)        return a.second &lt; b.second;    return a.first &gt; b.first;&#125;int main()&#123;    /* ==================== 1. swap 交换 ==================== */    int a = 1;    int b = 2;    cout &lt;&lt; &quot;before swap: &quot; &lt;&lt; a &lt;&lt; &quot; &quot; &lt;&lt; b &lt;&lt; endl;    swap(a, b);    cout &lt;&lt; &quot;after  swap: &quot; &lt;&lt; a &lt;&lt; &quot; &quot; &lt;&lt; b &lt;&lt; endl &lt;&lt; endl;    /* ==================== 2. sort + 内置比较器 ==================== */    vector&lt;int&gt; c = &#123; 1, 3, 1, 4, 5, 2, 0 &#125;;    sort(c.begin(), c.end(), greater&lt;int&gt;());    cout &lt;&lt; &quot;sorted c (descending): &quot;;    for (int x : c)        cout &lt;&lt; x &lt;&lt; &quot; &quot;;    cout &lt;&lt; endl &lt;&lt; endl;    /* ==================== 3. sort + 自定义比较器 ==================== */    vector&lt;pair&lt;int, int&gt;&gt; d = &#123; &#123;1, 9&#125;, &#123;2, 9&#125;, &#123;6, 1&#125;, &#123;7, 0&#125; &#125;;    sort(d.begin(), d.end(), cmp);    cout &lt;&lt; &quot;sorted pairs:&quot; &lt;&lt; endl;    for (auto p : d)        cout &lt;&lt; p.first &lt;&lt; &quot; &quot; &lt;&lt; p.second &lt;&lt; endl;    cout &lt;&lt; endl;    /* ==================== 4. lower_bound（二分查找） ==================== */    vector&lt;int&gt; arr = &#123; 0, 1, 1, 1, 8, 9, 9 &#125;;    int pos = lower_bound(arr.begin(), arr.end(), 8) - arr.begin();    cout &lt;&lt; &quot;lower_bound of 8 index: &quot; &lt;&lt; pos &lt;&lt; endl &lt;&lt; endl;    /* ==================== 5. reverse 区间反转 ==================== */    reverse(arr.begin() + 2, arr.begin() + 6);    cout &lt;&lt; &quot;after reverse [2,6): &quot;;    for (int x : arr)        cout &lt;&lt; x &lt;&lt; &quot; &quot;;    cout &lt;&lt; endl &lt;&lt; endl;    /* ==================== 6. min 初始化列表 ==================== */    cout &lt;&lt; &quot;min of &#123;1,3,4,5&#125; = &quot; &lt;&lt; min(&#123; 1, 3, 4, 5 &#125;) &lt;&lt; endl &lt;&lt; endl;    /* ==================== 7. 去重（sort + unique） ==================== */    sort(arr.begin(), arr.end());    arr.erase(unique(arr.begin(), arr.end()), arr.end());    cout &lt;&lt; &quot;after unique: &quot;;    for (int x : arr)        cout &lt;&lt; x &lt;&lt; &quot; &quot;;    cout &lt;&lt; endl &lt;&lt; endl;    /* ==================== 8. 常见数学函数 ==================== */    cout &lt;&lt; &quot;abs(-1.0) = &quot; &lt;&lt; abs(-1.0) &lt;&lt; endl;    cout &lt;&lt; &quot;pow(2,3) = &quot; &lt;&lt; pow(2, 3) &lt;&lt; endl;    cout &lt;&lt; &quot;sqrt(2) = &quot; &lt;&lt; sqrt(2) &lt;&lt; endl;    cout &lt;&lt; &quot;ceil(2.1) = &quot; &lt;&lt; ceil(2.1) &lt;&lt; endl;    cout &lt;&lt; &quot;floor(2.1) = &quot; &lt;&lt; floor(2.1) &lt;&lt; endl;    cout &lt;&lt; &quot;round(3.4) = &quot; &lt;&lt; round(3.4) &lt;&lt; endl &lt;&lt; endl;    /* ==================== 9. 整数技巧 ==================== */    cout &lt;&lt; &quot;(a+b-1)/b 上取整示例: &quot; &lt;&lt; (7 + 3 - 1) / 3 &lt;&lt; endl &lt;&lt; endl;    /* ==================== 10. gcd / lcm（手写版） ==================== */    int x = 8, y = 12;    cout &lt;&lt; &quot;gcd(&quot; &lt;&lt; x &lt;&lt; &quot;, &quot; &lt;&lt; y &lt;&lt; &quot;) = &quot; &lt;&lt; gcd(x, y) &lt;&lt; endl;    cout &lt;&lt; &quot;lcm(&quot; &lt;&lt; x &lt;&lt; &quot;, &quot; &lt;&lt; y &lt;&lt; &quot;) = &quot; &lt;&lt; lcm(x, y) &lt;&lt; endl;    return 0;&#125;
STL_优先队列#include&lt;iostream&gt;#include&lt;queue&gt;#include&lt;vector&gt;int main()&#123;	std::priority_queue&lt;int,std::vector&lt;int&gt;,std::greater&lt;int&gt;&gt;pque;	pque.push(1);	std::cout &lt;&lt; pque.top() &lt;&lt; std::endl;	pque.push(3);	std::cout &lt;&lt; pque.top() &lt;&lt; std::endl;	pque.push(2);	std::cout &lt;&lt; pque.top() &lt;&lt; std::endl;	pque.push(4);	std::cout &lt;&lt; pque.top() &lt;&lt; std::endl;	pque.pop();	std::cout &lt;&lt; pque.top() &lt;&lt; std::endl;	return 0;&#125;
模板#include&lt;iostream&gt;using namespace std;//函数模版template&lt;typename T&gt;T getAbs(T a)&#123;	if (a &gt;= 0)		return a;	else		return -a;&#125;//类模板template&lt;typename T,int size&gt;class Data &#123;	T data[size];public:	Data()	&#123;		cout &lt;&lt; &quot;input&quot;&lt;&lt;size&lt;&lt;&quot;datas:&quot;&lt;&lt;endl;		for (int i = 0; i &lt; size; i++) &#123;			cin &gt;&gt; data[i];		&#125;	&#125;	void show()	&#123;		cout &lt;&lt; size &lt;&lt; &quot;datas:&quot; &lt;&lt; endl;		for (int i = 0; i &lt; size; i++) &#123;			cout &lt;&lt;data[i]&lt;&lt;endl;		&#125;	&#125;	T getMax();&#125;;template&lt;typename T, int size&gt;T Data&lt;T, size&gt;::getMax()&#123;	T _max = data[0];	for (int i = 0; i &lt; size; i++) &#123;		if (data[i] &gt; _max) &#123;			_max = data[i];		&#125;	&#125;	return _max;&#125;int main()&#123;	Data&lt;int, 5&gt; d;	d.show();	cout &lt;&lt; d.getMax() &lt;&lt; endl;	int ia = -5;	float fa = 3.14f;	double da = -1.23456;	int ic = getAbs(ia);	cout &lt;&lt; ic&lt;&lt; endl;	float fc = getAbs(fa);	cout &lt;&lt; fc&lt;&lt; endl;	double dc = getAbs(da);	cout &lt;&lt; dc&lt;&lt; endl;&#125;
数据结构与算法排序算法#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;ctime&gt;#include &lt;algorithm&gt;   // 提供 swap、max_element 等算法函数#include &quot;排序.h&quot;using namespace std;// ------------------------------------------------------------// 排序算法口诀：// 插冒归很稳，选冒插会方，n老快归堆// ------------------------------------------------------------// ======================== 冒泡排序 ========================// 思想：不断比较相邻元素，把最大的“冒泡”到数组末尾void bubblesort(vector&lt;int&gt;&amp; arr)&#123;    int size = arr.size();        // 当前数组长度    bool swapped = false;         // 标记本轮是否发生过交换    // 外层循环：控制排序的轮数    for (int i = 0; i &lt; size - 1; i++)    &#123;        swapped = false;          // 每一轮开始前重置标志        // 内层循环：两两比较相邻元素        // size - 1 - i 是因为后 i 个元素已经排好序        for (int j = 0; j &lt; size - 1 - i; j++)        &#123;            // 如果前一个元素比后一个大，说明顺序错误            if (arr[j] &gt; arr[j + 1])            &#123;                swap(arr[j], arr[j + 1]);  // 交换相邻元素                swapped = true;             // 记录发生了交换            &#125;        &#125;        // 如果整一轮都没有交换，说明数组已经有序        if (!swapped) break;    &#125;&#125;// ======================== 选择排序 ========================// 思想：每一轮从未排序区间中选择最小值，放到当前位置void selectsort(vector&lt;int&gt;&amp; arr)&#123;    int size = arr.size();    // 外层循环：确定当前要放“最小值”的位置 i    for (int i = 0; i &lt; size - 1; i++)    &#123;        int minpos = i;   // 假设当前位置 i 就是最小值位置        // 在 [i+1, size) 区间中寻找真正的最小值        for (int j = i + 1; j &lt; size; j++)        &#123;            if (arr[j] &lt; arr[minpos])            &#123;                minpos = j;   // 更新最小值下标            &#125;        &#125;        // 如果最小值不在当前位置，则交换        if (minpos != i)        &#123;            swap(arr[i], arr[minpos]);        &#125;    &#125;&#125;// ======================== 插入排序 ========================// 思想：将当前元素插入到前面已经排好序的区间中void insertsort(vector&lt;int&gt;&amp; arr)&#123;    int size = arr.size();    // 默认第 0 个元素已经“有序”，从第 1 个开始插入    for (int i = 1; i &lt; size; i++)    &#123;        int temp = arr[i];    // 保存当前待插入的元素        int j = i - 1;        // 从已排序区间的末尾开始比较        // 只要前面的元素比 temp 大，就整体后移        while (j &gt;= 0 &amp;&amp; arr[j] &gt; temp)        &#123;            arr[j + 1] = arr[j];  // 元素向后挪一位            j--;        &#125;        // j 停止的位置后一个，正好是 temp 的插入点        arr[j + 1] = temp;    &#125;&#125;// ======================== 希尔排序 ========================// 思想：分组插入排序，逐步缩小间隔，提高效率void shellsort(vector&lt;int&gt;&amp; arr)&#123;    int size = arr.size();    // gap 为分组间隔，从大到小逐步缩小    for (int gap = size / 2; gap &gt; 0; gap /= 2)    &#123;        // 对每一组做“插入排序”        for (int i = gap; i &lt; size; i++)        &#123;            int temp = arr[i];  // 当前要插入的元素            int j = i;            // 在同一组内向前比较并移动            while (j &gt;= gap &amp;&amp; arr[j - gap] &gt; temp)            &#123;                arr[j] = arr[j - gap];                j -= gap;            &#125;            // 插入到正确位置            arr[j] = temp;        &#125;    &#125;&#125;// ======================== 快速排序 ========================// 思想：选定基准值，将数组划分为左右两部分（分治）void quicksort(vector&lt;int&gt;&amp; arr, int left, int right)&#123;    // 递归终止条件：区间长度 &lt;= 1    if (left &gt;= right) return;    // 选取中间元素作为基准值（避免极端情况）    int pivot = arr[(left + right) / 2];    int i = left;    // 左指针    int j = right;   // 右指针    // 一次划分过程    while (i &lt;= j)    &#123;        // 从左向右找到第一个 &gt;= pivot 的元素        while (arr[i] &lt; pivot) i++;        // 从右向左找到第一个 &lt;= pivot 的元素        while (arr[j] &gt; pivot) j--;        // 若左右指针未交错，交换这两个元素        if (i &lt;= j)        &#123;            swap(arr[i], arr[j]);            i++;            j--;        &#125;    &#125;    // 递归处理左右子区间    quicksort(arr, left, j);    quicksort(arr, i, right);&#125;// ======================== 堆排序 ========================// 功能：调整以 parent 为根的子树，使其满足大顶堆性质void heapAdjust(vector&lt;int&gt;&amp; arr, int len, int parent)&#123;    int largest = parent;           // 假设父节点最大    int left = 2 * parent + 1;      // 左孩子下标    int right = 2 * parent + 2;     // 右孩子下标    // 若左孩子存在且比父节点大    if (left &lt; len &amp;&amp; arr[left] &gt; arr[largest])        largest = left;    // 若右孩子存在且比当前最大值还大    if (right &lt; len &amp;&amp; arr[right] &gt; arr[largest])        largest = right;    // 如果最大值不是父节点，则交换并继续向下调整    if (largest != parent)    &#123;        swap(arr[parent], arr[largest]);        heapAdjust(arr, len, largest);    &#125;&#125;void heapsort(vector&lt;int&gt;&amp; arr)&#123;    int n = arr.size();    if (n == 0) return;    // 建立初始大顶堆（从最后一个非叶子节点开始）    for (int i = (n - 1) / 2; i &gt;= 0; i--)    &#123;        heapAdjust(arr, n, i);    &#125;    // 不断将堆顶最大值放到数组末尾    for (int i = n - 1; i &gt; 0; i--)    &#123;        swap(arr[0], arr[i]);       // 最大值归位        heapAdjust(arr, i, 0);      // 重新调整剩余堆    &#125;&#125;// ======================== 归并排序 ========================// 思想：递归拆分 + 有序合并void mergeSort(vector&lt;int&gt;&amp; arr, int left, int right, vector&lt;int&gt;&amp; temp)&#123;    // 区间只有一个元素时，天然有序    if (left &gt;= right) return;    int mid = left + (right - left) / 2;    // 递归拆分左右区间    mergeSort(arr, left, mid, temp);    mergeSort(arr, mid + 1, right, temp);    int i = left;       // 左区间指针    int j = mid + 1;    // 右区间指针    int idx = 0;        // 临时数组下标    // 合并两个有序区间    while (i &lt;= mid &amp;&amp; j &lt;= right)    &#123;        temp[idx++] = (arr[i] &lt; arr[j]) ? arr[i++] : arr[j++];    &#125;    // 将剩余元素直接复制    while (i &lt;= mid)  temp[idx++] = arr[i++];    while (j &lt;= right) temp[idx++] = arr[j++];    // 将合并结果写回原数组    for (int k = 0; k &lt; idx; k++)    &#123;        arr[left + k] = temp[k];    &#125;&#125;// ======================== 基数排序（修正版） ========================// 思想：按数位进行稳定排序（个位 → 十位 → 百位）void radixSort(vector&lt;int&gt;&amp; arr)&#123;    int maxVal = *max_element(arr.begin(), arr.end());  // 找最大值确定位数    // exp 控制当前处理的数位：1=个位，10=十位...    for (int exp = 1; maxVal / exp &gt; 0; exp *= 10)    &#123;        vector&lt;vector&lt;int&gt;&gt; bucket(10);  // 0~9 共 10 个桶        // 按当前数位分配到对应桶中        for (int num : arr)        &#123;            int digit = (num / exp) % 10;            bucket[digit].push_back(num);        &#125;        int index = 0;        // 按桶顺序收集元素，保持稳定性        for (auto&amp; b : bucket)        &#123;            for (int num : b)            &#123;                arr[index++] = num;            &#125;        &#125;    &#125;&#125;// ======================== 主函数 ========================int main()&#123;    srand(time(NULL));   // 设置随机数种子    vector&lt;int&gt; data;    cout &lt;&lt; &quot;排序的原始数据:\n&quot;;    // 生成 10 个 1~100 的随机数    for (int i = 0; i &lt; 10; i++)    &#123;        data.push_back(rand() % 100 + 1);        cout &lt;&lt; data.back() &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; endl;    vector&lt;int&gt; temp(data.size());  // 归并排序用的辅助数组    cout &lt;&lt; &quot;排序之后的数据:\n&quot;;    // 选择一种排序算法进行测试    // bubblesort(data);    // selectsort(data);    // insertsort(data);    // shellsort(data);    // quicksort(data, 0, data.size() - 1);    // heapsort(data);    // mergeSort(data, 0, data.size() - 1, temp);    radixSort(data);    // 输出排序结果    for (int num : data)    &#123;        cout &lt;&lt; num &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; endl;    return 0;&#125;
