oid reverse() &#123;		Node* prev = nullptr;		Node* curr = head;		while (curr != nullptr) &#123;			Node* nextTemp = curr-&gt;next; 			curr-&gt;next = prev;			prev = curr;			curr = nextTemp;		&#125;		head = prev; // 最后别忘了把头接回来	&#125;	void print() &#123;		if (head == nullptr)			return;		Node* curr = head;		while (curr != nullptr) &#123;			cout &lt;&lt; curr-&gt;value &lt;&lt; &quot; &quot;;			curr = curr-&gt;next;		&#125;		&#125;&#125;;int main()&#123;	MyLinkList List;	List.addHead(10);	List.addHead(5);	List.addTail(20);	List.insert(1, 15);	List.addTail(25);	List.print();	List.reverse();	List.print();&#125;
