newNode = new ListNode(val);		ListNode* curr = nullptr;		if (index &lt; size / 2) &#123;			curr = head;			for (int i = 0; i &lt; index; i++) &#123;				curr = curr-&gt;next;			&#125;		&#125;		else&#123;			curr = tail;			for (int i = 0; i &lt; size-index; i++) &#123;				curr = curr-&gt;prev;			&#125;		&#125;		newNode-&gt;next = curr;		newNode-&gt;prev = curr-&gt;prev;		curr-&gt;prev-&gt;next = newNode;		curr-&gt;prev = newNode;		size++;	&#125;	void printForward()const &#123;		ListNode* curr = head;		if (curr == nullptr) &#123;			return;		&#125;		else &#123;			while (curr != tail-&gt;next) &#123;				cout &lt;&lt; curr-&gt;val &lt;&lt; &quot; &quot;;				curr = curr-&gt;next;			&#125;		&#125;		cout &lt;&lt; endl;	&#125;	void printBackward()const &#123;		ListNode* curr = tail;		if (curr == nullptr) &#123;			return;		&#125;		else &#123;			while (curr != head-&gt;prev) &#123;				cout &lt;&lt; curr-&gt;val &lt;&lt; &quot; &quot;;				curr = curr-&gt;prev;			&#125;		&#125;		cout &lt;&lt; endl;	&#125;	void solveJosephus(int m) &#123;		if (size &lt;= 1) &#123;			cout &lt;&lt; &quot;最后的幸运儿是&quot; &lt;&lt; head-&gt;val &lt;&lt; &quot;号&quot; &lt;&lt; endl;			return;		&#125;		tail-&gt;next = head;		head-&gt;prev = tail;		ListNode* curr = head;		while (size &gt;1) &#123;			for (int i = 1; i &lt; m; ++i) &#123;				curr = curr-&gt;next;			&#125;			ListNode* temp = curr;					temp-&gt;prev-&gt;next = temp-&gt;next;			temp-&gt;next-&gt;prev = temp-&gt;prev;			cout &lt;&lt; &quot;编号为&quot; &lt;&lt; temp-&gt;val &lt;&lt; &quot;的同学离开了圈子&quot; &lt;&lt; endl;			curr = temp-&gt;next;			delete temp;			size--;				&#125;		cout &lt;&lt; &quot;最后的幸运儿是&quot; &lt;&lt; curr-&gt;val &lt;&lt; &quot;号&quot; &lt;&lt; endl;		delete curr;		head = tail = nullptr;		size = 0;	&#125;&#125;;int main()&#123;	MyDoubleLinkList List;	List.addHead(10);	List.addHead(20);	List.addTail(30);	List.addTail(40);	List.insert(3, 50);	List.printForward();	List.printBackward();	List.solveJosephus(3);&#125;
