动态数组#include&lt;iostream&gt;using namespace std;template &lt;typename T&gt;class MyVector &#123;private:	T* data;	int curr_size;	int capacity;public:	MyVector() :data(new T[2]), curr_size(0), capacity(2) &#123;&#125;;   ~MyVector() &#123;		delete[]data;	&#125;   bool isEmpty() const &#123;	   return curr_size == 0;   &#125;	void pushBack(T value) &#123;		if (curr_size == capacity) &#123;			resize();		&#125;		data[curr_size] = value;		curr_size++;	&#125;	void resize() &#123;		capacity *= 2;		T* newdata = new T[capacity];		for (int i = 0; i &lt; curr_size; i++) &#123;			newdata[i] = data[i];		&#125;		delete[]data;		data = newdata;	&#125;	//运算符重载代替get函数	T&amp; operator[](int index)&#123;		return data[index];	&#125;		/*T get(int index) &#123;		return data[index];	&#125;*/		int size() &#123;		return curr_size;	&#125;	void insert(int index, T value) &#123;		if (index &gt; capacity || index &lt; 0)			return ;		if (curr_size == capacity) &#123;			resize();		&#125;		for (int i = curr_size; i &gt;index; i--) &#123;			data[i] = data[i-1];		&#125;		data[index] = value;		curr_size++;	&#125;	void erase(int index) &#123;		if (index&lt;0 || index&gt;curr_size) &#123;			return;		&#125;		for (int i = index; i &lt; curr_size-1; ++i) &#123;			data[i] = data[i+1];		&#125;		curr_size--;	&#125;&#125;;int main()&#123;	MyVector&lt;int&gt; arr;	arr.pushBack(10);	arr.pushBack(20);	arr.pushBack(30);	arr.insert(1, 15);	arr.erase(2);	for (int i = 0; i &lt; arr.size(); i++) &#123;		cout &lt;&lt; arr[i] &lt;&lt; &quot; &quot;;	&#125;	return 0;&#125;
堆#include&lt;iostream&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;using namespace std;class MyHeap &#123;private:	vector&lt;int&gt;heap;	//当前节点下标为i,则左子节点下标为2i+1;右子节点下标为2i+2;	//父节点为(i-1)/2;public:	MyHeap() &#123;&#125;	void siftup() &#123;		int size = heap.size();		int i = size - 1;		while(i&gt;0)&#123;			if (heap[i] &lt;= heap[(i - 1) / 2]) &#123;				break;			&#125;			if (heap[i] &gt; heap[(i - 1) / 2])			&#123;				swap(heap[i], heap[(i - 1) / 2]);			&#125;			i = (i - 1) / 2;		&#125;	&#125;	void push(int val) &#123;		heap.push_back(val);		siftup();	&#125;	void siftdown(int i, int n) &#123;  // i 当前节点，n 堆大小		while (true) &#123;			int left = 2 * i + 1;			int right = 2 * i + 2;			int largest = i;  // 先假设自己最大			// 左孩子存在且更大			if (left &lt; n &amp;&amp; heap[left] &gt; heap[largest]) &#123;				largest = left;			&#125;			// 右孩子存在且更大			if (right &lt; n &amp;&amp; heap[right] &gt; heap[largest]) &#123;				largest = right;			&#125;			// 如果自己不是最大，交换并继续下沉			if (largest != i) &#123;				swap(heap[i], heap[largest]);				i = largest;  // 继续看下一层			&#125;			else &#123;				break;  // 已经满足堆性质，停止			&#125;		&#125;	&#125;		void pop() &#123;		if (heap.empty()) &#123;			return;		&#125;		heap[0] = heap.back();		heap.pop_back();		if (!heap.empty()) &#123;			siftdown(0, heap.size());		&#125;	&#125;	int top()const &#123;		return heap[0];	&#125;	bool empty()const &#123;		return heap.empty();	&#125;	void print() const &#123;		for (int val : heap) cout &lt;&lt; val &lt;&lt; &quot; &quot;;		cout &lt;&lt; endl;	&#125;&#125;;int main()&#123;	MyHeap h;	h.push(50);	h.push(30);	h.push(80);	h.push(40);	h.push(20);	h.push(70);	h.push(90);	h.print();	while (!h.empty()) &#123;		cout &lt;&lt; h.top() &lt;&lt; &quot; &quot;;		h.pop();	&#125;	cout &lt;&lt; endl;		return 0;&#125;
栈#include&lt;iostream&gt;using namespace std;#include&lt;string&gt;#include&lt;vector&gt;/*#define MAXSIZE 100 //宏定义不加等号和分号typedef int ElemType;//定义ElemType为int类型;class Stack&#123;//定义栈类public:	ElemType data [MAXSIZE];	int top;//栈顶指针实质为数组下标,不是指针;&#125;;void initStack(Stack* s)//初始化栈&#123;	s-&gt;top = -1;//初始化栈顶指针&#125;int isEmpty(Stack* s)//判断栈是否为空&#123;	if (s-&gt;top != -1)	&#123;		cout &lt;&lt; &quot;栈为空&quot;;		return -1;	&#125;	else	&#123;		return 0;	&#125;&#125;int push(Stack* s,ElemType e)//压栈&#123;	if (s-&gt;top &gt;= MAXSIZE - 1)	&#123;		cout &lt;&lt; &quot;栈已满&quot;;		return -1;	&#125;	else	&#123;		s-&gt;top++;//栈顶指针向上移动,出事时为-1-&gt;0,即数组下标为零		s-&gt;data[s-&gt;top] = e;//将数据e压入栈中		return 0;	&#125;&#125;int pop(Stack* s,ElemType *e)//出栈,这里e为指针类型传参&#123;	if (s-&gt;top == -1)	&#123;		cout &lt;&lt; &quot;栈为空&quot;;		return -1;	&#125;	*e = s-&gt;data[s-&gt;top];	s-&gt;top--;	return 0;&#125;int gettop(Stack* s, ElemType* e)//得到栈顶元素&#123;	if (s-&gt;top == -1)	&#123;		cout &lt;&lt; &quot;栈为空&quot;;		return -1;	&#125;	*e = s-&gt;data[s-&gt;top]; &#125;int main()&#123;	int *a=new int;	Stack *s=new Stack;//在堆内开辟空间,也可以在初始化的时候开辟空间	initStack(s);	push(s, 100);	push(s, 1);	pop(s, a);//pop代表数据已经出栈了	cout &lt;&lt; *a&lt;&lt;&quot; &quot;;	push(s, 10);	pop(s, a);	cout &lt;&lt; *a &lt;&lt; &quot; &quot;;	gettop(s, a);	cout &lt;&lt; *a &lt;&lt; &quot; &quot;;	delete a;	delete s;	return 0;&#125;*///栈的链式结构中就相当于链表,用头插法相当于压栈;把头节点之后的元素当成栈顶;class MyStack &#123;private:	vector&lt;int&gt; data; public:	// 1. 入栈	void push(int val) &#123;		data.push_back(val);	&#125;	// 2. 出栈	void pop() &#123;		if (data.empty()) &#123;			return ;		&#125;		data.pop_back();	&#125;	// 3. 查看栈顶元素	int top() &#123;		return data[data.size() - 1];		if (data.size() == 0)		return -1; // 占位符	&#125;	// 5. 获取栈的大小	int size() &#123;		return data.size();	&#125;&#125;;int main()&#123;	MyStack s;	s.push(10);	s.push(20);	s.push(30);	s.push(40);	s.push(50);&#125;
队列#include&lt;iostream&gt;using namespace std;#include&lt;string&gt;#define MAXSIZE 100//队列先进先出class queue &#123;public:	int data[MAXSIZE];//队列长度	int front;//队头指针	int rear;//队尾指针,实际都为数组下标&#125;;void initqueue(queue* q)//队列初始化&#123;	q-&gt;front = 0;	q-&gt;rear = 0;&#125;int isempty(queue* q)//判断队列是否为空&#123;	if (q-&gt;front == q-&gt;rear)//自己写的都等于0不是普遍情况,		                    //例如入队四个又出队四个,                            //此时队列为空,且下标值!=0	&#123;		cout &lt;&lt; &quot;队列为空&quot; &lt;&lt; &quot; &quot;;		return -1;	&#125;	else		return 0;&#125;int outqueue(queue* q)//出队操作&#123;	if (q-&gt;front == q-&gt;rear)	&#123;		cout &lt;&lt; &quot;队列为空&quot; &lt;&lt; &quot; &quot;;		return -1;	&#125;	else	&#123;		int e = q-&gt;data[q-&gt;front];		q-&gt;front++;		return e;	&#125;		&#125;int queuefull(queue* q)//判断队满&#123;	if (q-&gt;front &gt; 0)//判断队头前面有没有空余	&#123;		int temp = q-&gt;front;//保存队头此时的值		for (int i = q-&gt;front; i &lt;= q-&gt;rear; i++)		&#123;			q-&gt;data[i - temp] = q-&gt;data[i];//意思就是把队列整体移到最前面		&#125;		q-&gt;front = 0;		q-&gt;rear = q-&gt;rear - temp;//此时队头和队尾下标		return 1;	&#125;	else	&#123;		cout &lt;&lt; &quot;队列已满&quot; &lt;&lt; &quot; &quot;;		return 0;	&#125;&#125;int inqueue(queue* q,int e)//入队操作&#123;	if (q-&gt;rear &gt;= MAXSIZE)	&#123;		if (!queuefull(q))		&#123;			return -1;		&#125;	&#125;	q-&gt;data[q-&gt;rear] = e;	q-&gt;rear++;	return 1;&#125;int gethead(queue* q, int* e)//得到队头元素&#123;	if (q-&gt;front == q-&gt;rear)	&#123;		cout &lt;&lt; &quot;队列为空&quot; &lt;&lt; &quot; &quot;;		return -1;	&#125;	else	&#123;		*e = q-&gt;data[q-&gt;front];		return 1;	&#125;	 &#125; int main() &#123;	queue q;	initqueue(&amp;q);	inqueue(&amp;q, 10);	inqueue(&amp;q, 20);	inqueue(&amp;q, 30);	inqueue(&amp;q, 40);	inqueue(&amp;q, 50);	cout &lt;&lt; outqueue(&amp;q) &lt;&lt; &quot; &quot;;	cout &lt;&lt; outqueue(&amp;q) &lt;&lt; &quot; &quot;;	int e;	gethead(&amp;q, &amp;e);	cout &lt;&lt; e;	return 0;&#125;
哈希表#include&lt;iostream&gt;#include&lt;vector&gt;using namespace std;struct Node &#123;	int value;	int key;	Node* next;	Node() :key(0), value(0), next(nullptr)&#123;&#125;	Node(int k,int v) :key(k), value(v), next(nullptr) &#123;&#125;&#125;;class MyHashMap &#123;private:	vector&lt;Node*&gt;table;	int capacity;	int hash(int key) &#123; return key % capacity; &#125;public:	MyHashMap(int cap=16)		:capacity(cap),		 table(cap,nullptr)&#123;&#125;	void put(int key,int value) &#123;		Node* curr = table[hash(key)];		Node* newNode = new Node(key, value);		if (table[hash(key)] ==nullptr) &#123;			table[hash(key)] = newNode;		&#125;		else &#123;			while (curr != nullptr) &#123;				if (curr-&gt;key == key) &#123;					curr-&gt;value = value;					return;				&#125;				curr = curr-&gt;next;			&#125;			newNode-&gt;next = table[hash(key)];			table[hash(key)] = newNode;						&#125;	&#125;	int get(int key) &#123;			Node* curr = table[hash(key)];			while (curr != nullptr) &#123;				if (curr-&gt;key == key) &#123;					return curr-&gt;value;				&#125;				curr = curr-&gt;next;			&#125;			return -1;			&#125;	void remove(int key) &#123;		Node* head = table[hash(key)];		Node* curr = head;		Node* prev = nullptr;		if (head == nullptr) &#123;			return;		&#125;		if (table[hash(key)]-&gt;key == key) &#123;			table[hash(key)] = table[hash(key)]-&gt;next;			delete head;			return;		&#125;		else &#123;			while (curr != nullptr) &#123;				if (curr-&gt;key == key) &#123;					prev-&gt;next = curr-&gt;next;					delete curr;					return;				&#125;				else				&#123;					prev = curr;					curr = curr-&gt;next;				&#125;			&#125;		&#125;	&#125;	void print() const &#123;		for (int i = 0; i &lt; capacity; i++) &#123;  // 遍历所有桶			cout &lt;&lt; &quot;桶 &quot; &lt;&lt; i &lt;&lt; &quot;: &quot;;			Node* curr = table[i];			if (curr == nullptr) &#123;				cout &lt;&lt; &quot;空&quot; &lt;&lt; endl;				continue;			&#125;			while (curr != nullptr) &#123;				cout &lt;&lt; &quot;(&quot; &lt;&lt; curr-&gt;key &lt;&lt; &quot;,&quot; &lt;&lt; curr-&gt;value &lt;&lt; &quot;) &quot;;				if (curr-&gt;next != nullptr) cout &lt;&lt; &quot;-&gt; &quot;;				curr = curr-&gt;next;			&#125;			cout &lt;&lt; endl;		&#125;		cout &lt;&lt; &quot;-------------------&quot; &lt;&lt; endl;	&#125;&#125;;int main() &#123;		MyHashMap map(10);  // 容量 10，方便看到冲突		cout &lt;&lt; &quot;=== 测试 put ===&quot; &lt;&lt; endl;		map.put(1, 100);		map.put(11, 200);   // 和 1 冲突（假设 hash 是 %10）		map.put(2, 300);		map.put(11, 999);   // 更新 11 的值		map.put(25, 500);		map.print();  // 看当前所有内容		cout &lt;&lt; &quot;=== 测试 get ===&quot; &lt;&lt; endl;		cout &lt;&lt; &quot;get(1) = &quot; &lt;&lt; map.get(1) &lt;&lt; endl;     // 100		cout &lt;&lt; &quot;get(11) = &quot; &lt;&lt; map.get(11) &lt;&lt; endl;   // 999（更新后）		cout &lt;&lt; &quot;get(2) = &quot; &lt;&lt; map.get(2) &lt;&lt; endl;     // 300		cout &lt;&lt; &quot;get(999) = &quot; &lt;&lt; map.get(999) &lt;&lt; endl; // -1（不存在）		cout &lt;&lt; &quot;=== 测试 remove ===&quot; &lt;&lt; endl;		map.remove(11);     // 删除 11		map.remove(999);    // 不存在，没事		map.remove(1);      // 删除 1		map.print();  // 看删除后的情况		cout &lt;&lt; &quot;get(11) 删除后 = &quot; &lt;&lt; map.get(11) &lt;&lt; endl;  // -1		return 0;&#125;
