 nullptr) &#123;//		return 0;//	&#125;//	else&#123;////			T-&gt;lh += find_height(T-&gt;lchild);//			T-&gt;rh += find_height(T-&gt;rchild);//		&#125;//		//	return max(T-&gt;lh, T-&gt;rh)+1;//	//&#125;//	////int main()//&#123;//	bitree T;//	createtree(&amp;T);////	preorder(T,&#x27;C&#x27;);//	cout &lt;&lt; endl;////	inorder(T);//	cout &lt;&lt; endl;////	bkorder(T);//	cout &lt;&lt; endl;////	levelorder(T);//	cout &lt;&lt; endl;////	cout &lt;&lt; find_height(T)&lt;&lt;endl;//&#125;struct TreeNode &#123;	char val;	TreeNode* right;	TreeNode* left;	TreeNode() :val(0), right(nullptr), left(nullptr) &#123;&#125;	TreeNode(char x):val(x),right(nullptr),left(nullptr)&#123;&#125;&#125;;string str = &quot;ABDH#K###E##CFI###G#J##&quot;;int index = 0;TreeNode* createtree() &#123;	if (index &gt;= str.size()) return nullptr;	char ch = str[index++];	if (ch == &#x27;#&#x27;) &#123;		return nullptr;  // # 表示空节点	&#125;	TreeNode* newNode = new TreeNode(ch);	newNode-&gt;left=createtree();	newNode-&gt;right = createtree();	return newNode;&#125;void inorder(TreeNode* root) &#123;	if (root == nullptr) &#123;		return;	&#125;	inorder(root-&gt;left);	cout &lt;&lt; root-&gt;val &lt;&lt; &quot; &quot;;	inorder(root-&gt;right);&#125;int main()&#123;	TreeNode* root=createtree();		inorder(root);	cout &lt;&lt; endl;	return 0;&#125;
图#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;cmath&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;queue&gt;using namespace std;const int MAXN = 300005;const int MAXLOG = 20;vector&lt;int&gt; tree[MAXN];int depth[MAXN];int parent[MAXN][MAXLOG];int w[MAXN];int ans[MAXN];int n, m;// 预处理LCAvoid dfs_lca(int u, int p) &#123;    depth[u] = depth[p] + 1;    parent[u][0] = p;    for (int i = 1; i &lt; MAXLOG; i++) &#123;        if (parent[u][i - 1] != -1) &#123;            parent[u][i] = parent[parent[u][i - 1]][i - 1];        &#125;        else &#123;            parent[u][i] = -1;        &#125;    &#125;    for (int v : tree[u]) &#123;        if (v != p) &#123;            dfs_lca(v, u);        &#125;    &#125;&#125;int lca(int u, int v) &#123;    if (depth[u] &lt; depth[v]) swap(u, v);    // 将u提到与v同一深度    for (int i = MAXLOG - 1; i &gt;= 0; i--) &#123;        if (parent[u][i] != -1 &amp;&amp; depth[parent[u][i]] &gt;= depth[v]) &#123;            u = parent[u][i];        &#125;    &#125;    if (u == v) return u;    // 同时上提    for (int i = MAXLOG - 1; i &gt;= 0; i--) &#123;        if (parent[u][i] != -1 &amp;&amp; parent[u][i] != parent[v][i]) &#123;            u = parent[u][i];            v = parent[v][i];        &#125;    &#125;    return parent[u][0];&#125;// 获取路径长度int path_length(int s, int t) &#123;    int l = lca(s, t);    return depth[s] + depth[t] - 2 * depth[l];&#125;// 获取路径上的第k个节点（从s开始）int get_kth_node(int s, int t, int k) &#123;    int l = lca(s, t);    int dist_s_to_l = depth[s] - depth[l];    if (k &lt;= dist_s_to_l) &#123;        // 在s到lca的路径上        int node = s;        for (int i = MAXLOG - 1; i &gt;= 0; i--) &#123;            if (k &gt;= (1 &lt;&lt; i)) &#123;                node = parent[node][i];                k -= (1 &lt;&lt; i);            &#125;        &#125;        return node;    &#125;    else &#123;        // 在lca到t的路径上        k = depth[t] - depth[l] - (k - dist_s_to_l);        int node = t;        for (int i = MAXLOG - 1; i &gt;= 0; i--) &#123;            if (k &gt;= (1 &lt;&lt; i)) &#123;                node = parent[node][i];                k -= (1 &lt;&lt; i);            &#125;        &#125;        return node;    &#125;&#125;int main() &#123;    ios::sync_with_stdio(false);    cin.tie(0);    cin &gt;&gt; n &gt;&gt; m;    // 读入树结构    for (int i = 0; i &lt; n - 1; i++) &#123;        int u, v;        cin &gt;&gt; u &gt;&gt; v;        tree[u].push_back(v);        tree[v].push_back(u);    &#125;    // 读入观察时间    for (int i = 1; i &lt;= n; i++) &#123;        cin &gt;&gt; w[i];    &#125;    // 初始化parent数组    memset(parent, -1, sizeof(parent));    depth[0] = -1;    dfs_lca(1, 0);    // 处理每个玩家    for (int i = 0; i &lt; m; i++) &#123;        int s, t;        cin &gt;&gt; s &gt;&gt; t;        int l = lca(s, t);        int len = path_length(s, t);        // 遍历整个路径，计算每个节点的时间        for (int time = 0; time &lt;= len; time++) &#123;            int node = get_kth_node(s, t, time);            if (time == w[node]) &#123;                ans[node]++;            &#125;        &#125;    &#125;    // 输出结果    for (int i = 1; i &lt;= n; i++) &#123;        cout &lt;&lt; ans[i];        if (i &lt; n) cout &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; endl;    return 0;&#125;
