线索二叉树#include&lt;iostream&gt;using namespace std;#include&lt;string&gt;class threadnode&#123;public:	char data;	threadnode* lchild;	threadnode* rchild;	int ltag;	int rtag;&#125;;typedef threadnode* threadtree;threadtree prev1;char str[] = &quot;ABDH##I##EJ###CF##G##&quot;;int idx = 0;void createtree(threadtree* T)&#123;	char ch;	ch = str[idx++];	if (ch == &#x27;#&#x27;)	&#123;		*T = NULL;	&#125; 	else	&#123;		* T = new threadnode;		(*T)-&gt;data = ch;		createtree(&amp;(*T)-&gt;lchild);		if ((*T)-&gt;lchild != NULL)		&#123;			(*T)-&gt;ltag = 0;		&#125;		createtree(&amp;(*T)-&gt;rchild);		if ((*T)-&gt;rchild != NULL)		&#123;			(*T)-&gt;rtag = 0;		&#125;	&#125;&#125;void threading(threadtree T)&#123;	if (T != NULL)	&#123;		threading(T-&gt;lchild);		if(T-&gt;lchild==NULL)		&#123;			T-&gt;ltag = 1;			T-&gt;lchild = prev1;		&#125;		if (prev1-&gt;rchild == NULL)		&#123;			prev1-&gt;rtag = 1;			prev1-&gt;rchild = T;		&#125;		prev1 = T;		threading(T-&gt;rchild);	&#125;&#125;void inorderthreading(threadtree* head, threadtree T)&#123;	*head = new threadnode;	(*head)-&gt;ltag = 0;	(*head)-&gt;ltag = 0;	(*head)-&gt;rchild =*head;	if (T == NULL)	&#123;		(*head)-&gt;lchild = *head;	&#125;	else	&#123;		(*head)-&gt;lchild = T;		prev1 = (*head);				threading(T);		prev1-&gt;rchild = *head;		prev1-&gt;rtag = 1;		(*head)-&gt;rchild = prev1;	&#125;	 &#125;void inorder(threadtree T)&#123;	threadtree curr;	curr = T-&gt;lchild;	while (curr != T)	&#123;		while (curr-&gt;ltag == 0)		&#123;			curr = curr-&gt;lchild;		&#125;		cout &lt;&lt; curr-&gt;data&lt;&lt;&quot; &quot;;		while (curr-&gt;rtag == 1 &amp;&amp; curr-&gt;rchild != T)		&#123;			curr = curr-&gt;rchild;			cout &lt;&lt; curr-&gt;data &lt;&lt; &quot; &quot;;		&#125;		curr = curr-&gt;rchild;	&#125;	printf(&quot;\n&quot;);&#125;int main()&#123;	threadtree head;	threadtree T;	createtree(&amp;T);	inorderthreading(&amp;head, T);	inorder(head);	return 0;&#125;
