智能指针//独占指针unique_ptr,删除拷贝构造函数和赋值函数//计数指针or共享指针shared_ptr,没有删除//弱指针weak_ptr,weak_ptr绑定到shared_ptr不会增加引用计数#include&lt;memory&gt;#include&lt;vector&gt;#include&lt;iostream&gt;using namespace std;class AA&#123;public:	string m_name;	AA() &#123; cout &lt;&lt; m_name &lt;&lt; &quot;调用构造函数AA().\n&quot;; &#125;	AA(const string&amp; name) :m_name(name) &#123; cout &lt;&lt; &quot;调用构造函数AA(&quot; &lt;&lt; m_name &lt;&lt; &quot;).\n&quot;; &#125;	~AA() &#123; cout &lt;&lt; &quot;调用了析构函数~AA()(&quot; &lt;&lt; m_name &lt;&lt; &quot;).\n&quot;; &#125;&#125;;class BB &#123;public:	string m_name;	BB() &#123; cout &lt;&lt; m_name &lt;&lt; &quot;调用构造函数BB().\n&quot;; &#125;	BB(const string&amp; name) :m_name(name) &#123; cout &lt;&lt; &quot;调用构造函数BB(&quot; &lt;&lt; m_name &lt;&lt; &quot;).\n&quot;; &#125;	~BB() &#123; cout &lt;&lt; &quot;调用了析构函数~BB()(&quot; &lt;&lt; m_name &lt;&lt; &quot;).\n&quot;; &#125;	&#125;;int main()&#123;	//AA* p = new AA(&quot;喵喵&quot;);	//unique_ptr&lt;AA&gt; p(p);//1.用已存在的地址初始化		//unique_ptr&lt;AA&gt; p(new AA(&quot;喵喵&quot;));//2.分配内存并初始化,可以用这个	//unique_ptr&lt;AA&gt;p = make_unique&lt;AA&gt;(&quot;AA类带参构造&quot;);//3.最推荐	AA* p0 = new AA(&quot;喵喵&quot;);	shared_ptr&lt;AA&gt;p2(p0);	shared_ptr&lt;AA&gt;p3(p2);//可使用拷贝构造	shared_ptr&lt;AA&gt;p4 = p2;//可赋值	shared_ptr&lt;BB&gt; p5= make_shared&lt;BB&gt;(&quot;汪汪&quot;);	cout &lt;&lt; &quot;p2.usecount()=&quot; &lt;&lt; p2.use_count() &lt;&lt; endl;//引用计数	cout &lt;&lt; &quot;p3.usecount()=&quot; &lt;&lt; p3.use_count() &lt;&lt; endl;	//注意事项:	//1.不能把普通指针直接赋值给智能指针,而是用地址初始化	//2.不能用其他unique_ptr进行拷贝构造	//3.不能用=对unique_ptr进行赋值	//以上均因为这是独占智能指针,可能导致对同一块内存释放多次&#125;
